import { useState } from "react";

import API from "../services/api";

function BudgetForm() {

  const [budget, setBudget] =
    useState("");



  const handleSubmit =
    async (e) => {

    e.preventDefault();

    try {

      await API.post(
        "/budget",
        {
          budget,
        }
      );

      alert(
        "Budget Saved"
      );

    } catch (error) {

      console.log(error);

      alert(
        "Budget Set Failed"
      );
    }
  };



  return (

    <div
      className="
      bg-white
      p-6
      rounded-xl
      shadow-lg
      mt-10
    "
    >

      <h2
        className="
        text-2xl
        font-bold
        mb-4
      "
      >
        Monthly Budget
      </h2>

      <form
        onSubmit={handleSubmit}
      >

        <input
          type="number"
          placeholder="Enter Budget"
          value={budget}
          onChange={(e) =>
            setBudget(
              e.target.value
            )
          }
          className="
          w-full
          border
          p-3
          mb-4
          rounded-lg
        "
        />

        <button
          type="submit"
          className="
          bg-green-500
          text-white
          px-6
          py-2
          rounded-lg
        "
        >
          Save Budget
        </button>

      </form>

    </div>
  );
}

export default BudgetForm;
